"use client";

import { useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { getRandomComplete } from "@/lib/learningMessages";

interface CalcStep {
  key: string;
  label: string;
  desc: string;
  expr: string;
  result: number;
}

// 阶段 1：平年 —— 2 月 28 天
const COMMON_STEPS: CalcStep[] = [
  { key: "big", label: "计算大月", desc: "7 个大月，每个 31 天", expr: "31 × 7 = 217", result: 217 },
  { key: "small", label: "计算小月", desc: "4 个小月，每个 30 天", expr: "30 × 4 = 120", result: 120 },
  { key: "feb", label: "计算 2 月", desc: "平年的 2 月", expr: "2 月 = 28 天", result: 28 },
  { key: "total", label: "求总和", desc: "把它们加起来", expr: "217 + 120 + 28 = 365", result: 365 },
];

// 阶段 2：闰年 —— 2 月 29 天
const LEAP_STEPS: CalcStep[] = [
  { key: "big", label: "计算大月", desc: "7 个大月，每个 31 天", expr: "31 × 7 = 217", result: 217 },
  { key: "small", label: "计算小月", desc: "4 个小月，每个 30 天", expr: "30 × 4 = 120", result: 120 },
  { key: "feb", label: "计算 2 月", desc: "闰年的 2 月多 1 天", expr: "2 月 = 29 天", result: 29 },
  { key: "total", label: "求总和", desc: "把它们加起来", expr: "217 + 120 + 29 = 366", result: 366 },
];

type Stage = "common" | "leap" | "done";

export default function CountPage() {
  const topicId = "calendar";
  const [stage, setStage] = useState<Stage>("common");
  const [commonRevealed, setCommonRevealed] = useState(0);
  const [leapRevealed, setLeapRevealed] = useState(0);
  const [completeMsg, setCompleteMsg] = useState("");

  const nextStep = getNextStep(topicId, "count");

  const revealCommon = (i: number) => {
    if (i !== commonRevealed) return;
    setCommonRevealed(i + 1);
  };

  const revealLeap = (i: number) => {
    if (i !== leapRevealed) return;
    const next = i + 1;
    setLeapRevealed(next);
    if (next >= LEAP_STEPS.length) {
      setCompleteMsg(getRandomComplete());
      setStage("done");
    }
  };

  const renderSteps = (
    steps: CalcStep[],
    revealed: number,
    onReveal: (i: number) => void,
    accent: string
  ) => (
    <div className="space-y-3">
      {steps.map((s, i) => {
        const isTotal = s.key === "total";

        if (i < revealed) {
          // 已揭示
          return (
            <div
              key={s.key}
              className={`animate-float-in flex items-center justify-between rounded-[var(--radius-sm)] border p-4 ${
                isTotal
                  ? "border-[var(--accent)] bg-[var(--accent)]/10"
                  : "border-[var(--border)] bg-[var(--bg-soft)]"
              }`}
            >
              <div>
                <div className="text-sm font-bold text-[var(--text)]">
                  {s.label}
                </div>
                <div className="text-xs text-[var(--text-secondary)]">
                  {s.desc}
                </div>
              </div>
              <div className="text-right">
                <div
                  className={`font-extrabold ${
                    isTotal
                      ? "text-xl text-[var(--accent)]"
                      : "text-lg text-[var(--primary)]"
                  }`}
                >
                  {s.expr}
                </div>
                {isTotal && (
                  <div className="text-xs font-bold text-[var(--accent-dark)]">
                    {s.result} 天
                  </div>
                )}
              </div>
            </div>
          );
        }

        if (i === revealed) {
          // 当前可点击
          return (
            <button
              key={s.key}
              onClick={() => onReveal(i)}
              className="flex w-full items-center justify-center gap-2 rounded-[var(--radius-sm)] px-4 py-4 text-base font-bold text-white shadow-[var(--shadow-sm)] transition-all hover:scale-[1.02] active:scale-95"
              style={{ backgroundColor: accent }}
            >
              {s.label} →
            </button>
          );
        }

        // 未到
        return (
          <div
            key={s.key}
            className="flex items-center justify-between rounded-[var(--radius-sm)] border-2 border-dashed border-[var(--signal-pending)] p-4 opacity-60"
          >
            <div className="text-sm font-medium text-[var(--text-muted)]">
              {s.label}
            </div>
            <div className="text-xs text-[var(--text-muted)]">待计算…</div>
          </div>
        );
      })}
    </div>
  );

  return (
    <StepShell topicId={topicId} stepId="count">
      <div className="space-y-6">
        {/* 阶段 1：平年 */}
        <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
          <div className="mb-1 flex items-center gap-2">
            <span className="rounded-full bg-[var(--primary)]/15 px-3 py-1 text-xs font-bold text-[var(--primary-dark)]">
              阶段 1
            </span>
            <h2 className="text-lg font-bold text-[var(--text)]">
              平年一年有多少天？
            </h2>
          </div>
          <p className="mb-4 text-sm text-[var(--text-secondary)]">
            把 12 个月分成三组来算：大月、小月、2 月。按顺序点按钮，一步步算出来。
          </p>

          {renderSteps(COMMON_STEPS, commonRevealed, revealCommon, "var(--primary)")}

          {commonRevealed >= COMMON_STEPS.length && stage === "common" && (
            <div className="mt-4 animate-float-in rounded-[var(--radius-sm)] border-2 border-[var(--accent3)] bg-[var(--accent3-light)]/30 p-4 text-center">
              <div className="text-sm font-bold text-[var(--text)]">
                平年一共{" "}
                <span className="text-2xl text-[var(--accent-dark)]">365</span>{" "}
                天
              </div>
              <button
                onClick={() => setStage("leap")}
                className="mt-3 rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                闰年会一样吗？看看 →
              </button>
            </div>
          )}
        </div>

        {/* 阶段 2：闰年 */}
        {stage !== "common" && (
          <div className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-5 shadow-[var(--shadow-sm)]">
            <div className="mb-1 flex items-center gap-2">
              <span className="rounded-full bg-[var(--accent2)]/20 px-3 py-1 text-xs font-bold text-[var(--accent2)]">
                阶段 2
              </span>
              <h2 className="text-lg font-bold text-[var(--text)]">
                闰年一年有多少天？
              </h2>
            </div>
            <p className="mb-4 text-sm text-[var(--text-secondary)]">
              闰年的 2 月有 29 天，比平年多 1 天。再算一次看看总数。
            </p>

            {renderSteps(LEAP_STEPS, leapRevealed, revealLeap, "var(--accent2)")}

            {leapRevealed >= LEAP_STEPS.length && (
              <div className="mt-4 animate-float-in rounded-[var(--radius-sm)] border-2 border-[var(--accent3)] bg-[var(--accent3-light)]/30 p-4 text-center">
                <div className="text-sm font-bold text-[var(--text)]">
                  闰年一共{" "}
                  <span className="text-2xl text-[var(--accent-dark)]">366</span>{" "}
                  天
                </div>
              </div>
            )}
          </div>
        )}

        {/* 对比 + 完成 */}
        {stage === "done" && (
          <div className="animate-float-in space-y-4">
            <div className="rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]">
              <h3 className="mb-4 text-center text-lg font-bold text-[var(--text)]">
                平年 vs 闰年
              </h3>
              <div className="grid grid-cols-2 gap-4">
                <div className="rounded-[var(--radius-sm)] bg-[var(--primary)]/10 p-4 text-center">
                  <div className="text-sm text-[var(--text-secondary)]">平年</div>
                  <div className="text-3xl font-extrabold text-[var(--primary)]">
                    365
                  </div>
                  <div className="text-xs text-[var(--text-muted)]">
                    2 月 28 天
                  </div>
                </div>
                <div className="rounded-[var(--radius-sm)] bg-[var(--accent2)]/15 p-4 text-center">
                  <div className="text-sm text-[var(--text-secondary)]">闰年</div>
                  <div className="text-3xl font-extrabold text-[var(--accent2)]">
                    366
                  </div>
                  <div className="text-xs text-[var(--text-muted)]">
                    2 月 29 天
                  </div>
                </div>
              </div>
              <div className="mt-4 text-center text-base font-bold text-[var(--accent-dark)]">
                闰年比平年多 1 天（29 − 28 = 1）
              </div>
            </div>

            <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
              <div className="text-5xl animate-bounce-soft">🔢</div>
              <h3 className="mt-3 text-xl font-bold text-[var(--text)]">
                {completeMsg}
              </h3>
              <p className="mt-2 text-sm text-[var(--text-secondary)]">
                平年 365 天，闰年 366 天——差别就在 2 月那多出来的一天！
              </p>
              <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
                <button
                  onClick={() => {
                    setStage("common");
                    setCommonRevealed(0);
                    setLeapRevealed(0);
                    setCompleteMsg("");
                  }}
                  className="rounded-full border border-[var(--border)] bg-[var(--bg-soft)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-card)]"
                >
                  再算一次
                </button>
                {nextStep && (
                  <Link
                    href={nextStep.path}
                    className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
                  >
                    下一步：{nextStep.label} →
                  </Link>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}
